import React, { useEffect, useState } from 'react'
import { Img_URL, fetchMovie } from '../../utils/fetchApi';
import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';

const TopRated = () => {
  const [page,setPage]=useState(1);
  const [TopRatedMovieList,setTopRatedMovieList]=useState([])

  const loadMoreHandle=()=>{
   setPage((prev)=> prev + 1);
  //  refetch();
   setTopRatedMovieList((prev)=> [...prev,...TopratedList]);
  //  console.log(TopRatedMovieList);
 }

  const { isLoading,isError,error ,data: TopratedList,refetch} = useQuery({
      queryKey: ["Movie", "TopratedList"],
      queryFn: () =>
        fetchMovie("top_rated",`${page}`).then((res) => {
          setTopRatedMovieList(res.results)
          return res.results;
        }),
    });



    useEffect(()=>{
      // refetch();
      // return()=>{
      //   refetch();
      // }
    },[page]);

    if (isLoading) {
      return (
        <div className="loading">
          <h1>Loading...</h1>
        </div>
      );
    } else if (isError) {
      return (
        <div className="error">
          <p>{error.message}</p>
        </div>
      );
    } else
return (
  <div className="Popular">
        <h1>Top-Rated Movies</h1>
        <div>
        {TopRatedMovieList?.map((item,index) => (
            <Link to={`/movie/${item.id}`} className="card" key={index}>
              <img src={`${Img_URL}${item.poster_path}`} alt="img" />
            </Link>
        ))}
        </div>
        <button onClick={loadMoreHandle}>More</button>
      </div>
)
}

export default TopRated
